-- 3. Faversham × Lead Capture
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'lead-capture',
  'faversham',
  'Faversham attracts a particular type of visitor: someone who appreciates quality, seeks out independent businesses, and is willing to spend for the right experience. These visitors arrive at Abbey Street, browse Standard Quay, tour Shepherd Neame, and visit the market. They discover businesses they genuinely like, but the commercial relationship often ends when they leave town. A visitor who loved your creek-side restaurant leaves without joining your mailing list. A market day shopper who admired your craft products goes home and forgets your name. A homeowner impressed by a local tradesperson''s work loses the business card. Without systematic lead capture, Faversham businesses lose the ongoing relationship that transforms a single visit into a lifetime customer. We build lead capture systems specifically for Faversham''s quality-focused market, designed to turn one-time visitors into repeat customers, subscribers, and advocates.',
  'Faversham''s lead generation patterns are shaped by its market town character and visitor economy. Weekly market visitors browse briefly and leave. Abbey Street shoppers discover businesses during leisurely walks. Standard Quay visitors arrive for the creek-side atmosphere and discover food producers incidentally. Shepherd Neame brewery tour visitors are in town for a specific duration and open to discovering other businesses. The common thread is time-limited visits where contact capture must be quick, natural, and valuable to the visitor.',
  'Lead capture sophistication in Faversham is minimal. Some food producers collect email addresses at market stalls, but few have systematic digital capture. Restaurants rarely capture diner details beyond booking platforms they do not control. Retailers on Abbey Street almost never capture visitor information. The businesses that do build mailing lists and follow-up systems report dramatically higher repeat visit rates, demonstrating the untapped potential across the wider Faversham business community.',
  'We design Faversham lead capture around the visitor journey. Market day browsers get QR codes linking to exclusive online offers that require an email address. Restaurant diners get post-meal emails with loyalty incentives. Abbey Street shoppers get in-store WiFi splash pages with newsletter signup. Online visitors get content-led capture offering Faversham guides, recipes, or behind-the-scenes content from local producers. Every mechanism offers genuine value in exchange for contact details.',
  '{"population": 20000, "business_districts": ["Market Place", "Abbey Street", "Standard Quay", "Faversham Creek"], "key_fact": "Quality-focused visitor demographic with high potential for repeat business and loyalty"}',
  '[{"title": "Market day visitors leaving without any contact captured", "description": "Faversham Market draws hundreds of visitors weekly. They browse, purchase, enjoy the atmosphere, and leave. The vast majority take no business card, join no mailing list, and have no way to reorder or recommend specific stallholders. Each market day, potential long-term customer relationships walk out of Market Place uncaptured."}, {"title": "Restaurant diners lost to booking platform intermediaries", "description": "Faversham restaurants that rely on third-party booking platforms surrender their customer data to the platform. The diner who loved your creek-side restaurant receives follow-up from the platform, not from you. Without direct lead capture, your best customers remain strangers you cannot reach."}, {"title": "One-time Abbey Street visitors never becoming repeat customers", "description": "A visitor discovers a beautiful independent shop on Abbey Street during a Faversham day trip. They make a purchase, leave, and within a week have forgotten the shop name. Without capturing their email address and sending a follow-up, the lifetime value of that customer is limited to a single spontaneous purchase."}]',
  '[{"title": "Market day QR capture converting browsers to subscribers", "description": "We create QR-code-driven capture systems for Faversham market stallholders and town centre businesses. Visitors scan a code to access exclusive offers, recipes, or product information, providing their email address in exchange. Market day foot traffic becomes a growing subscriber list you can market to year-round."}, {"title": "Direct diner capture bypassing third-party platforms", "description": "We build post-dining capture systems that collect customer details directly. Wi-Fi splash pages, QR-linked feedback forms with loyalty incentives, and email-based receipt systems all capture diner information that belongs to your Faversham restaurant, not to a booking platform. Your customers, your data, your follow-up."}, {"title": "Content-led online capture for Faversham artisan businesses", "description": "Visitors to your Faversham website receive offers of genuine value: recipe collections from local producers, seasonal guides to Abbey Street shops, or behind-the-scenes brewery content. These content assets capture email addresses from engaged prospects who have already demonstrated interest in Faversham''s independent business scene."}]',
  '[{"question": "What type of lead capture works for a market town like Faversham?", "answer": "Faversham''s quality-focused visitors respond best to value-exchange capture. Rather than aggressive pop-ups, we use content offers, loyalty incentives, and QR-driven market day promotions. The key is offering something genuinely valuable in exchange for contact details, matching the artisan quality your visitors expect."}, {"question": "Can lead capture help my Faversham food business build a mailing list?", "answer": "Absolutely. We build capture systems across every touchpoint: market stalls, your physical premises, your website, and social media. Most Faversham food producers see their mailing list grow by hundreds of subscribers within the first few months, providing a direct marketing channel they own and control."}, {"question": "Will pop-ups and forms feel pushy for my Faversham shop visitors?", "answer": "Our capture mechanisms are designed to feel natural in Faversham''s independent business context. In-store WiFi splash pages, tasteful QR codes, and value-led website offers feel like good hospitality rather than aggressive marketing. We match the tone and quality your Abbey Street or creek-side customers expect."}, {"question": "How do I follow up with captured leads?", "answer": "We set up automated email sequences that welcome new subscribers, share your story, and present relevant offers. A market day visitor receives a welcome email featuring your best products. A restaurant diner gets a loyalty incentive for their next visit. The follow-up runs automatically while you focus on your Faversham business."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
