-- 6. Faversham × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'faversham',
  'Faversham''s independent business scene is perfectly suited to social media, yet most businesses here are not taking advantage. The photogenic creek at Standard Quay, the medieval streetscape of Abbey Street, the bustling market, and the Shepherd Neame brewery heritage create content opportunities that other towns would envy. Visitors already photograph and share Faversham experiences on Instagram and Facebook constantly, creating a stream of user-generated content that local businesses could leverage but rarely do. A food producer at Standard Quay whose products appear in visitor Instagram stories without any tagged business profile is invisible to the hundreds of followers who see that content. We set up and optimise social media profiles for Faversham businesses so they are positioned to capture the organic attention this beautiful market town naturally generates.',
  'Faversham''s social media landscape is driven by visual content. Instagram activity around Standard Quay, the creek, and Abbey Street is substantial, with visitors sharing atmospheric photos throughout the year. Facebook community groups for Faversham are active with local recommendations and business reviews. The Faversham Market generates social buzz weekly. Shepherd Neame''s brewery tours create branded social content that spills into the wider Faversham conversation. Food and drink content performs exceptionally well, given the town''s growing culinary reputation.',
  'Social media quality in Faversham is mixed. A few food producers and hospitality businesses maintain strong Instagram presences, but the majority of businesses have either dormant profiles or none at all. The gap between Faversham''s photogenic physical reality and its digital social presence is significant. Businesses that invest in proper social media setup stand out dramatically in a market where most competitors are absent or inactive.',
  'We set up Faversham social media profiles with the visual quality this town demands. Instagram profiles get professional imagery reflecting the creek-side, medieval, and market town aesthetic. Facebook pages are built for community engagement and recommendation requests. Google Business Profiles are fully optimised for visitor and local discovery. Every profile is branded consistently and loaded with location-specific content that makes your Faversham business discoverable.',
  '{"population": 20000, "business_districts": ["Market Place", "Abbey Street", "Standard Quay", "Faversham Creek"], "key_fact": "Highly photogenic town generating strong organic social media content from visitors"}',
  '[{"title": "Visitor Instagram content going untagged and uncaptured", "description": "Visitors to Standard Quay, Abbey Street, and the creek photograph and share Faversham experiences daily. But when they tag a location without finding your business profile, the exposure benefits the town generally rather than your business specifically. Every untagged visitor photo is a missed marketing opportunity."}, {"title": "Dormant Faversham business Facebook pages undermining credibility", "description": "A potential customer searches for your Faversham business on Facebook and finds a page last updated eighteen months ago. In a town that prides itself on active, thriving independence, a dormant social media presence suggests a business that is no longer operating or does not care about its public image."}, {"title": "No social media presence for Faversham community recommendations", "description": "Faversham Facebook groups regularly feature requests for trade recommendations, restaurant suggestions, and shopping advice. Businesses without active, professional social profiles cannot benefit from these recommendation threads. When someone mentions your name, the prospect has nothing credible to click through to."}]',
  '[{"title": "Instagram profiles matching Faversham''s photogenic character", "description": "We set up and optimise Instagram profiles with professional imagery that reflects Faversham''s visual appeal. Creek-side settings, medieval architecture, and market atmosphere create a feed that feels authentically Faversham. Hashtag strategy and location tagging ensure you appear when visitors and locals search for Faversham businesses."}, {"title": "Community-optimised Facebook for Faversham recommendations", "description": "We build Facebook profiles designed for the Faversham community conversation. Complete service information, prominent reviews, professional branding, and shareable content that looks credible when someone recommends you in a local group. Your profile becomes the reference point when your business name comes up."}, {"title": "Multi-platform consistency for Faversham independents", "description": "Instagram, Facebook, Google Business Profile, and additional platforms as needed. Every profile carries consistent Faversham-specific branding and complete business information. No orphaned profiles, no outdated details. Your independent business presents a unified, professional image across every platform visitors and locals check."}]',
  '[{"question": "Which social media platforms matter most for Faversham businesses?", "answer": "Instagram is essential for food, hospitality, and retail businesses given Faversham''s photogenic character. Facebook is critical for community engagement and local recommendations. Google Business Profile influences both search rankings and visitor decisions. We set up the platforms that match your specific Faversham customer base."}, {"question": "Can Instagram actually drive footfall to my Abbey Street shop?", "answer": "Yes. Visitors planning Faversham trips regularly browse location-tagged Instagram content to discover shops and experiences. A well-maintained profile with professional imagery and clear location information directly influences visitor itineraries. Several Faversham businesses report that customers mention discovering them through Instagram."}, {"question": "I do not have time to take professional photos for social media.", "answer": "We provide guidance on taking quality smartphone photos that match Faversham''s aesthetic. Standard Quay, Abbey Street, and the creek provide naturally photogenic backdrops. We can also arrange a professional photography session to create a bank of images for your initial profile setup and ongoing content."}, {"question": "How do I handle negative comments on Faversham community groups?", "answer": "We provide response templates and guidance for engaging with all types of community feedback. In Faversham''s tight-knit community, how you respond to criticism is as important as the praise you receive. Professional, authentic responses build trust and often turn critics into advocates."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
